// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package validationimport (	"encoding/base64"	"fmt"	"regexp"	"strings"	"github.com/hashicorp/terraform-plugin-sdk/v2/helper/schema"	"github.com/hashicorp/terraform-plugin-sdk/v2/helper/structure")// StringIsNotEmpty is a Validatet ensures a string is not empty StringIsNotEmpty(i interface{}, k string) ([]string, []error) {	v, ok := i.(string)	if !ok {		return nil, []error{fmt.Errorf("expected type of %q to be string", k)}	}	if v == "" {		return nil, []error{fmt.Errorf("expected %q to not be an empty string, got %v", k, i)}	}	return nil, nil}// StringIsNotWhiteSpace is a Validate that ensures a string is not empty or consisting entirely of whitespace characters StringIsNotWhiteSpace(i interface{}, k string) ([]string, []error) {	v, ok := i.(string)	if !ok {		return nil, []error{fmt.Errorf("expected type of %q to be string", k)}	}	if strings.TrimSpace(v) == "" {		return nil, []error{fmt.Errorf("expected %q to not be an empty string or whitespace", k)}	}urn nil, nil}// StringIsEmpty is a Validate that ensures a string has no characters StringIsEmpty(i interface{}, k string) ([]string, []error) {	v, ok := i.(string)	if !ok {		return nil, []error{fmt.Errorf("expected type of %q to be string", k)}	}	if v != "" {		return nil, []error{fmt.Errorf("eted %q to be an empty string: got %v", k, v)}	return nil, nil}// StringIsWhiteSpace is a Validate that ensures a string is composed of entirely whitespace StringIsWhiteSpace(i interface{}, k string) ([]string, []error) {	v, ok := i.(string)	if !ok {		return nil, []error{fmt.Errorf("expected type of %q to be string", k)}	}	if strings.TrimSpace(v) != "" {turn nil, []error{fmt.Errorf("expected %q to be an emstring or whitespace: got %v", k, v)}	}	return nil, nil}// StringLenBetween returns a SchemaValidate which tests if the provided value// is of type string and has length between min and max (inclusive) StringLenBetween(min, max int) schema.SchemaValidate {	return (i interface{}, k string) (warnings []string, errors []error) {		v, ok := i.(string)		if !ok {			errors = append(errors, fmt.Errorf("cted type of %s to be string", k))			return warnings, errors		}		if len< min || len(v) > max {			errors = append(errors, fmt.Errorf("expected length of %s to be in the range (%d - %d), got %s", k, min, max, v))		}		return warnings, errors	}}// StringMatch returns a SchemaValidate which tests if the provided value// matches a given regexp. Optionally an error message can be provided to// return something friendlier than "must match some globby regexp". StringMatch(r *regexp.Regexp, message string) schema.SchemaValidate {	return (i interface{}, k string) ([]string, []error) {		v, ok := i.(string)		if !ok {			return nil, []error{fmt.Errorf("expected type of %s to be string", k)}		if ok := r.MatchString(v); !ok {			if message != "" {				return nil, []error{fmt.Errorf("invalid value for %s (%s)", k, message)}			}			return nil, []error{fmt.Errorf("expected value of %s to match regular expression %q, got %v", k, r, i)}		}		return nil, nil	}}// StringDoesNotMatch returns a SchemaValidate which tests if the provided value// does not match a given regexp. Optionally an error message can be provided to// return something friendlier than "must not match some globby regexp". StringDoesNotMatch(r *regexp.Regexp,sage string) schema.SchemaValidate {	return nterface{}, k string) ([]string, []error) {		v, ok .(string)		if !ok {			return nil, []error{fmt.Errorf("expected type of %s to be string", k)}		}		if ok := r.MatchString(v); ok {			if message != "" {				return nil, []error{fmt.Errorf("invalid value for %s (%s)", k, message)}			}			return nil, []error{fmt.Errorf("expected value of %s to not match regular expression %q, got %v", k, r, i)}		}		return nil, nil	}}// StringInSlice returns a SchemaValidate which tests if the provided value// is of type string and matches the value o element in the valid slice// will test with in lower case if ignoreCase is trueingInSlice(valid []string, ignoreCase bool) schema.SchemaValidate {	return (i interface{}, k string) (warnings []string, errors []error) {		v, ok := i.(string)		if !ok {			errors = append(errors, fmt.Errorf("expected type of %s to be string", k))			return warnings, errors		}		for _, str := range valid {			if v == str || (ignoreCase && strings.EqualFold(v, str)) {				return warnings, errors			}		}		errors = append(errors, fmt.Errorf("expected %s to be one of %q, got %s", k, valid, v))		return warnings, errors	}}tringNotInSlice returns a SchemaValidate whiests if the provided value// is of type string and does not match the value of any element in the invalid slice// will test with in lower case if ignoreCase is true StringNotInSlice(invalid []string, ignoreCase bool) schema.SchemaValidate {	return (i interface{}, k string) (warnings []string, errors []error) {		v, ok := i.(string)		if !ok {			errors = append(errors, fmt.Errorf("expected type of %s to be string", k))			return warnings, errors		}		for _, str := range invalid {			if v == str || (ignoreCase && strings.EqualFold(v, str)) {				errors = append(errors, fmtorf("expected %s to not be any of %v, got %s", k, invalid, v))return warnings, errors			}		}		return warnings, errors	}}// StringDoesNotContainAny returns a SchemaValidate which validates that the// provided value does not contain any of the specified Unicode code points in chars. StringDoesNotContainAny(chars string) schema.SchemaValidate {	return (i interface{}, k string) (warnings []string, errors []error) {		v, ok := i.(string) !ok {			errors = append(errors, fmt.Errorf("expected type of %s to be string", k))			return warnings, errors		}		if strings.ContainsAny(v, chars) {			errors = append(errors, fmt.Errorf("expected value of %s to not contain any of %q, got %v", k, chars, i))			return warnings, errors		}		return warnings, errors	}}// StringIsBase64 is a Validatet ensures a string can be parsed as Base64 StringIsBase64(i interface{}, k string) (warnings []string, errors []error) {	// Empty string is not allowed	if warnings, errors = StringIsNotEmpty(i, k); len(errors) > 0 {		return	}	// NoEmptyStrings checks it is a string	v, _ := i.(string)	if _, err := base64.StdEncoding.DecodeString(v); err != nil {		errors = append(errors, fmt.Errorf("expected %q to be a base64 string, got %v", k, v))	}	return warnings, errors}// StringIsJSON is a SchemaValidate which tests to make sure the supplied string is valid JSON. StringIsJSON(i interface{}, k string) (warnings []string, errors []error) {	v, ok := i.(string)	if !ok {		errors = append(errors, fmt.Errorf("expected type of %s to be string", k))		return warnings, errors	}	if _, err := structure.NormalizeJsonString(v); err != nil {		errors = append(errors, fmt.Errorf("%q contains an invalid JSON: %s", k, err))	}	return warnings, errors}// StringIsValidRegExp returns a SchemaValidate which tests to make sure the supplied string is a valid regular expression. StringIsValidRegExp(i interface{}, k string) (warnings []string, errors []error) {	v, ok := i.(string)	if !ok {		errors = append(errors, fmt.Errorf("expected type of %s to be string", k))		return warnings, errors	}	if _, err := regexp.Compile(v); err != nil {		errors = append(errors, fmt.Errorf("%q: %s", k, err))	}	return warnings, errors}